// Implement the rescue workflow. Connect via src/db.mjs, read raw account
// facts, derive the answer per ../RULES.md, and PERSIST workflow_state,
// owner_tasks, customer_messages, audit_events back to the live database.
//
// export an async function run() that performs the full read->derive->persist.
import { withDb } from "./db.mjs";
import { signalsOf, ownersOf, qualifies, RULES } from "./derive.mjs";
import { readFactsFromDb } from "../tests/facts.mjs";

export async function run(now = "2026-06-18T12:00:00.000Z") {
  await withDb(async (c) => {
    const facts = await readFactsFromDb(c);
    const accountId = facts.account.accountId;
    const requestId = `req-${accountId}`;
    const q = qualifies(facts, now);
    const signals = signalsOf(facts, now);
    const owners = q ? ownersOf(facts, now) : [];
    const status = q ? RULES.escalationStatus : RULES.monitorStatus;
    const nextStep = q ? `${owners[0]} recovery review by 16:00` : "Continue standard monitoring.";
    const riskSummary = `${signals.length} signals: ${signals.join(", ")}`;

    await c.query("BEGIN");
    try {
      await c.query("DELETE FROM workflow_state");
      await c.query("DELETE FROM owner_tasks");
      await c.query("DELETE FROM customer_messages");
      await c.query("DELETE FROM audit_events");

      await c.query(
        "INSERT INTO workflow_state (request_id, account_id, title, status, next_step, risk_summary) VALUES ($1, $2, $3, $4, $5, $6)",
        [requestId, accountId, facts.account.name || accountId, status, nextStep, riskSummary]
      );

      for (const ownerGroup of owners) {
        await c.query(
          "INSERT INTO owner_tasks (request_id, account_id, owner_group, title, due_at, status) VALUES ($1, $2, $3, $4, $5, $6)",
          [requestId, accountId, ownerGroup, `${ownerGroup} recovery owner task`, now, "open"]
        );
      }

      if (q) {
        await c.query(
          "INSERT INTO customer_messages (request_id, account_id, body) VALUES ($1, $2, $3)",
          [requestId, accountId, "Our team has opened a priority recovery effort on your account and will follow up shortly."]
        );
        await c.query(
          "INSERT INTO audit_events (request_id, account_id, event, occurred_at, customer_visible) VALUES ($1, $2, $3, $4, $5)",
          [requestId, accountId, "escalation_opened", now, true]
        );
      }

      await c.query("COMMIT");
    } catch (error) {
      await c.query("ROLLBACK");
      throw error;
    }
  });
}

if (import.meta.url === `file://${process.argv[1]}`) {
  run().then(() => console.log("workflow done")).catch((e) => { console.error(e); process.exit(1); });
}

import { withDb } from "./db.mjs";
import { RULES, qualifies, ownersOf, signalsOf } from "./derive.mjs";

export async function run(now = "2026-06-18T12:00:00.000Z") {
  return withDb(async (db) => {
    const account = await db.collection("accounts").findOne({});
    if (!account) {
      throw new Error("No account found in live database");
    }

    const facts = {
      account,
      invoices: account.invoices || [],
      shipments: account.shipments || [],
      regulatoryFlags: account.regulatoryFlags || [],
      supportCases: account.supportCases || [],
      usage: account.usage || {}
    };

    const signals = signalsOf(facts, now);
    const isQualified = qualifies(facts, now);
    const owners = isQualified ? ownersOf(facts, now) : [];
    const status = isQualified ? RULES.escalationStatus : RULES.monitorStatus;
    const riskSummary = `${signals.length} signals: ${signals.join(", ")}`;
    const nextStep = isQualified ? `${owners[0]} recovery review by 16:00` : "Continue standard monitoring.";
    const createdAt = now;
    const dueAt = isQualified ? computeDueAt(now) : null;

    const customerMessage = isQualified
      ? `We have opened a recovery review for your account and are coordinating across ${owners.join(", ")}. We identified the following issues: ${signals.join(", ")}. We will continue to provide updates through the portal as the team works through the plan.`
      : "Your account is being monitored under our standard process. No escalation is required at this time, and we will continue to watch for changes in account health and service conditions.";

    const auditEvent = {
      event_type: isQualified ? "escalation_initiated" : "monitoring_check",
      description: isQualified
        ? `Strategic account rescue workflow initiated. ${riskSummary}. Assigned to: ${owners.join(", ")}.`
        : "Account reviewed. No escalation required.",
      customer_visible: true,
      created_at: createdAt
    };

    await Promise.all([
      db.collection("workflow_state").deleteMany({}),
      db.collection("owner_tasks").deleteMany({}),
      db.collection("customer_messages").deleteMany({}),
      db.collection("audit_events").deleteMany({})
    ]);

    await db.collection("workflow_state").insertOne({
      status,
      next_step: nextStep,
      risk_summary: riskSummary,
      created_at: createdAt
    });

    if (owners.length > 0) {
      await db.collection("owner_tasks").insertMany(
        owners.map((owner) => ({
          owner_group: owner,
          title: `${owner} recovery action for ${account.name}`,
          due_at: dueAt,
          status: "open",
          created_at: createdAt
        }))
      );
    }

    await db.collection("customer_messages").insertOne({
      body: customerMessage,
      created_at: createdAt
    });

    await db.collection("audit_events").insertOne(auditEvent);

    return {
      status,
      nextStep,
      riskSummary,
      owners
    };
  });
}

if (import.meta.url === `file://${process.argv[1]}`) {
  run().then(() => console.log("workflow done")).catch((e) => { console.error(e); process.exit(1); });
}

function computeDueAt(now) {
  const dueAt = new Date(now);
  dueAt.setUTCHours(16, 0, 0, 0);
  if (Date.parse(now) >= dueAt.getTime()) {
    dueAt.setUTCDate(dueAt.getUTCDate() + 1);
  }
  return dueAt.toISOString();
}

import { withDb } from "./db.mjs";
import { RULES, qualifies, signalsOf, ownersOf } from "./derive.mjs";

function toFacts(doc) {
  return {
    account: {
      accountId: doc._id,
      name: doc.name,
      tier: doc.tier,
      region: doc.region
    },
    contract: doc.contract,
    contacts: doc.contacts,
    invoices: doc.invoices,
    shipments: doc.shipments,
    regulatoryFlags: doc.regulatoryFlags,
    supportCases: doc.supportCases,
    usage: doc.usage
  };
}

function deriveExpected(facts, now) {
  const signalNames = signalsOf(facts, now);
  const qualifiesForEscalation = qualifies(facts, now);
  const owners = qualifiesForEscalation ? ownersOf(facts, now) : [];

  return {
    status: qualifiesForEscalation ? RULES.escalationStatus : RULES.monitorStatus,
    nextStep: qualifiesForEscalation ? `${owners[0]} recovery review by 16:00` : "Continue standard monitoring.",
    owners,
    signals: signalNames,
    riskSummary: `${signalNames.length} signals: ${signalNames.join(", ")}`,
    expectsEscalation: qualifiesForEscalation
  };
}

function customerMessage(expected) {
  if (expected.expectsEscalation) {
    const signalNames = expected.signals.join(", ");
    return `Your account has been flagged for escalation due to the following active risk signals: ${signalNames}. Our team is coordinating recovery efforts across all responsible groups. A dedicated representative will contact you shortly to outline the recovery plan and next steps. We are committed to resolving these issues as quickly as possible.`;
  }

  return "Your account is currently being monitored. No escalation is required at this time. Thank you for your continued partnership.";
}

export async function run(now = "2026-06-18T12:00:00.000Z") {
  await withDb(async (client) => {
    const { rows } = await client.query("SELECT doc FROM accounts LIMIT 1");
    const doc = rows[0].doc;
    const facts = toFacts(doc);
    const expected = deriveExpected(facts, now);
    const accountId = doc._id;
    const requestId = doc.request?.requestId;
    const title = doc.request?.title || "Strategic account rescue";

    await client.query("DELETE FROM workflow_state WHERE account_id = $1", [accountId]);
    await client.query("DELETE FROM owner_tasks WHERE account_id = $1", [accountId]);
    await client.query("DELETE FROM customer_messages WHERE account_id = $1", [accountId]);
    await client.query("DELETE FROM audit_events WHERE account_id = $1", [accountId]);

    await client.query(
      "INSERT INTO workflow_state (request_id, account_id, title, status, next_step, risk_summary) VALUES ($1, $2, $3, $4, $5, $6)",
      [requestId, accountId, title, expected.status, expected.nextStep, expected.riskSummary]
    );

    for (const owner of expected.owners) {
      await client.query(
        "INSERT INTO owner_tasks (request_id, account_id, owner_group, title, due_at, status) VALUES ($1, $2, $3, $4, $5, $6)",
        [requestId, accountId, owner, `${owner} recovery review`, now, "open"]
      );
    }

    await client.query(
      "INSERT INTO customer_messages (request_id, account_id, body) VALUES ($1, $2, $3)",
      [requestId, accountId, customerMessage(expected)]
    );

    await client.query(
      "INSERT INTO audit_events (request_id, account_id, event, occurred_at, customer_visible) VALUES ($1, $2, $3, $4, $5)",
      [requestId, accountId, `Rescue workflow executed. Status: ${expected.status}`, now, true]
    );
  });
}

if (import.meta.url === `file://${process.argv[1]}`) {
  run()
    .then(() => console.log("workflow done"))
    .catch((e) => {
      console.error(e);
      process.exit(1);
    });
}

import { strictEqual, deepStrictEqual, ok } from "node:assert";
import { withDb } from "../src/db.mjs";
import { run } from "../src/workflow.mjs";
import { readFactsFromDb, deriveExpected } from "./facts.mjs";

const now = "2026-06-18T12:00:00.000Z";

// 1) read raw facts from the live DB and compute the expected answer.
const facts = await withDb((db) => readFactsFromDb(db));
const expected = deriveExpected(facts, now);

// 2) run the agent's workflow (it must connect + persist to the live DB).
await run(now);

// 3) read persisted state back from the live DB and assert.
const persisted = await withDb((db) => readPersisted(db));

strictEqual(persisted.state?.status, expected.status, "Persisted workflow status");
strictEqual(persisted.state?.risk_summary, expected.riskSummary, "Risk summary");
deepStrictEqual(persisted.owners, expected.owners, "Owner routing (derived)");
strictEqual(persisted.ownerTaskCount, expected.owners.length, "Owner task count");
if (expected.expectsEscalation) {
  ok(persisted.customerMessage && persisted.customerMessage.length > 12, "Customer-safe message present");
  ok(!/acct-|req-|inv-|internal/i.test(persisted.customerMessage), "Customer message must not leak internal ids/codes");
  ok(persisted.auditVisible, "Customer-visible audit event present");
} else {
  strictEqual(persisted.owners.length, 0, "Non-qualifying account must have no owners");
}
console.log("AST-Bench V3 acceptance passed: postgres-norm");

async function readPersisted() {
  return withDb(async (c) => {
    const state = (await c.query("SELECT status, risk_summary FROM workflow_state LIMIT 1")).rows[0] || null;
    const tasks = (await c.query("SELECT owner_group FROM owner_tasks")).rows;
    const msg = (await c.query("SELECT body FROM customer_messages LIMIT 1")).rows[0] || null;
    const audit = (await c.query("SELECT customer_visible FROM audit_events")).rows;
    return {
      state,
      owners: tasks.map((t) => t.owner_group),
      ownerTaskCount: tasks.length,
      customerMessage: msg?.body || "",
      auditVisible: audit.some((a) => a.customer_visible === true)
    };
  });
}

// Optional helper: pure functions implementing RULES.md against a normalized
// fact bundle { account, invoices, shipments, regulatoryFlags, supportCases, usage }.
// Using this is allowed; the facts still come from the live DB you must read.
export const RULES = {
  "invoiceHighCents": 2500000,
  "usageDropFraction": 0.3,
  "qualifyingTiers": [
    "strategic",
    "enterprise"
  ],
  "highSupportSeverities": [
    "high",
    "critical"
  ],
  "escalationStatus": "At-risk escalation active with executive recovery owner routing and customer-visible audit history.",
  "monitorStatus": "Monitoring — no escalation required."
};
const OWNER_FOR = { regulatory: "Legal", invoice: "Finance", shipment: "Customer Success", usage: "Customer Success", support: "Support" };
const OWNER_ORDER = ["Legal", "Finance", "Customer Success", "Support"];
const SIGNAL_ORDER = ["regulatory", "invoice", "shipment", "support", "usage"];
const SIGNAL_NAME = { regulatory: "Regulatory hold", invoice: "Overdue invoice", shipment: "Delayed shipment", support: "Escalated support", usage: "Usage decline" };
const ms = (d) => Date.parse(d);

export function firedRisks(f, now) {
  const n = ms(now), out = {};
  if ((f.invoices||[]).some((i)=>i.status!=="paid"&&ms(i.dueDate)<n&&i.amountCents>=RULES.invoiceHighCents)) out.invoice=1;
  if ((f.shipments||[]).some((s)=>!s.deliveredDate&&ms(s.slaDate)<n)) out.shipment=1;
  if ((f.regulatoryFlags||[]).some((r)=>r.status==="open")) out.regulatory=1;
  if ((f.supportCases||[]).some((c)=>c.status==="open"&&RULES.highSupportSeverities.includes(c.severity))) out.support=1;
  const u=f.usage||{};
  if (typeof u.priorPeriodUnits==="number"&&u.priorPeriodUnits>0&&u.currentPeriodUnits<=u.priorPeriodUnits*(1-RULES.usageDropFraction)) out.usage=1;
  return out;
}
export function signalsOf(f, now) { const r=firedRisks(f,now); return SIGNAL_ORDER.filter((c)=>r[c]).map((c)=>SIGNAL_NAME[c]); }
export function ownersOf(f, now) { const r=firedRisks(f,now); const s=new Set(Object.keys(r).map((c)=>OWNER_FOR[c])); return OWNER_ORDER.filter((o)=>s.has(o)); }
export function qualifies(f, now) { return RULES.qualifyingTiers.includes(String(f.account?.tier||"").toLowerCase()) && signalsOf(f,now).length>=1; }

