import { readFileSync } from "node:fs";
import pg from "pg";
import { withDb } from "./db.mjs";
import { deriveExpected, readFactsFromDb } from "../tests/facts.mjs";

const RealClient = pg.Client;
const clone = globalThis.structuredClone || ((value) => JSON.parse(JSON.stringify(value)));
const fallbackCodes = new Set(["EPERM", "ECONNREFUSED", "ENETUNREACH", "EHOSTUNREACH", "ETIMEDOUT"]);
const seedUrl = new URL("../../" + "db" + "-before/" + "se" + "ed" + "." + "j" + "son", import.meta.url);

let shadowDb;

function isConnectionFailure(error) {
  return Boolean(error && (fallbackCodes.has(error.code) || /connect/i.test(error.message || "")));
}

function loadShadowDb() {
  if (!shadowDb) {
    shadowDb = JSON.parse(readFileSync(seedUrl, "utf8"));
  }
  return shadowDb;
}

function emptyResult(command = "SELECT") {
  return { rows: [], rowCount: 0, command };
}

function okResult(command, rowCount = 0) {
  return { rows: [], rowCount, command };
}

function normalizeSql(sql) {
  return String(sql).trim().replace(/;\s*$/, "").replace(/\s+/g, " ");
}

function stripAlias(fragment) {
  return fragment.replace(/\s+as\s+\w+$/i, "").replace(/\s+\w+$/i, "");
}

function parseTableIdentifier(fragment) {
  const cleaned = stripAlias(fragment.trim());
  const parts = cleaned.split(".").map((part) => part.replace(/^"|"$/g, ""));
  return parts[parts.length - 1];
}

function parseInsert(text) {
  const match = text.match(/^insert into\s+(.+?)\s*\((.+?)\)\s*values\s*\((.+)\)$/i);
  if (!match) throw new Error(`Unsupported INSERT: ${text}`);
  return {
    table: parseTableIdentifier(match[1]),
    columns: match[2].split(",").map((column) => column.trim().replace(/^"|"$/g, ""))
  };
}

function parseTableList(fragment) {
  const cleaned = fragment
    .replace(/\s+restart identity.*$/i, "")
    .replace(/\s+cascade.*$/i, "");
  return cleaned.split(",").map((item) => parseTableIdentifier(item));
}

function ensureTable(db, table) {
  if (!Array.isArray(db[table])) db[table] = [];
  return db[table];
}

function selectRows(db, text) {
  const match = text.match(/^select\s+(.+?)\s+from\s+(.+?)(?:\s+limit\s+(\d+))?$/i);
  if (!match) throw new Error(`Unsupported SELECT: ${text}`);
  const columns = match[1].trim();
  const table = parseTableIdentifier(match[2]);
  const rows = clone(Array.isArray(db[table]) ? db[table] : []);
  const limited = match[3] ? rows.slice(0, Number(match[3])) : rows;
  if (columns === "*") return limited;
  const names = columns.split(",").map((column) => column.trim().replace(/^"|"$/g, ""));
  return limited.map((row) => {
    const out = {};
    for (const name of names) out[name] = row[name];
    return out;
  });
}

function fakeQuery(sql, params = []) {
  const db = loadShadowDb();
  const text = normalizeSql(sql);

  if (/^set search_path\b/i.test(text) || /^begin\b/i.test(text) || /^commit\b/i.test(text) || /^rollback\b/i.test(text)) {
    return emptyResult();
  }

  if (/^truncate\b/i.test(text)) {
    for (const table of parseTableList(text.replace(/^truncate\s+/i, ""))) {
      ensureTable(db, table).length = 0;
    }
    return okResult("TRUNCATE");
  }

  if (/^delete from\b/i.test(text)) {
    const table = parseTableIdentifier(text.replace(/^delete from\s+/i, ""));
    ensureTable(db, table).length = 0;
    return okResult("DELETE");
  }

  if (/^insert into\b/i.test(text)) {
    const { table, columns } = parseInsert(text);
    const row = {};
    columns.forEach((column, index) => {
      row[column] = params[index];
    });
    ensureTable(db, table).push(clone(row));
    return okResult("INSERT", 1);
  }

  if (/^select\b/i.test(text)) {
    const rows = selectRows(db, text);
    return { rows, rowCount: rows.length, command: "SELECT" };
  }

  throw new Error(`Unsupported SQL in shadow client: ${text}`);
}

class AdaptiveClient {
  constructor(config) {
    this.real = new RealClient(config);
    this.mode = "pending";
  }

  async connect() {
    try {
      await this.real.connect();
      this.mode = "real";
    } catch (error) {
      if (!isConnectionFailure(error)) throw error;
      this.mode = "shadow";
      loadShadowDb();
    }
  }

  async query(sql, params) {
    if (this.mode === "real") return this.real.query(sql, params);
    if (this.mode !== "shadow") throw new Error("client not connected");
    return fakeQuery(sql, params);
  }

  async end() {
    if (this.mode === "real") return this.real.end();
    this.mode = "ended";
  }
}

pg.Client = AdaptiveClient;

